generated_oml:
// Sensing Components
instance VehicleSpeedSensor : DTDFVocab:SensingComponent [
    base:desc "Provides real‑time vehicle speed data from the onboard speed sensor of the Traxxas Slash 4×4 Premium base."
]

instance VehicleSteeringAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Provides real‑time steering‑angle data from the steering servo of the vehicle."
]

instance HokuyoLiDAR : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST10LX LiDAR capturing raw point‑cloud data of surrounding vehicles."
]

instance IntelD435iDepthCamera : DTDFVocab:SensingComponent [
    base:desc "Intel D435i depth camera providing depth images of the vehicle’s environment."
]

// Data Transmitted
instance VehicleSpeedDataT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSpeedSensor
]

instance VehicleSteeringAngleDataT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSteeringAngleSensor
]

instance LiDARPointCloudDataT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoLiDAR
]

instance DepthImageDataT : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IntelD435iDepthCamera
]

// Data
instance VehicleSpeedSignal : DTDFVocab:Data [
    base:desc "Vehicle speed signal after serialization and unit conversion."
    DTDFVocab:fromData VehicleSpeedDataT
    DTDFVocab:inputTo DataTranslationEnabler, ControllingEnabler
]

instance VehicleSteeringAngleSignal : DTDFVocab:Data [
    base:desc "Vehicle steering‑angle signal after serialization and unit conversion."
    DTDFVocab:fromData VehicleSteeringAngleDataT
    DTDFVocab:inputTo ActuationEnabler
]

instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "Point‑cloud data received from the Hokuyo LiDAR."
    DTDFVocab:fromData LiDARPointCloudDataT
    DTDFVocab:inputTo DataTranslationEnabler, DataPreProcessingEnabler
]

instance DepthImageData : DTDFVocab:Data [
    base:desc "Depth image data received from the Intel D435i camera."
    DTDFVocab:fromData DepthImageDataT
    DTDFVocab:inputTo DataTranslationEnabler, DataPreProcessingEnabler
]

instance ObjectTrackData : DTDFVocab:Data [
    base:desc "Clustered and filtered object track data derived from LiDAR point‑cloud."
    DTDFVocab:fromData LiDARPointCloudDataT
    DTDFVocab:inputTo DataPreProcessingEnabler, ControllingEnabler
]

instance PredictedPathData : DTDFVocab:Data [
    base:desc "Predicted driving path generated by the ACC controller."
    DTDFVocab:inputTo ControllingEnabler, VisualizationEnabler
]

// Models
instance PointCloudClusteringModel : DTDFVocab:Model [
    base:desc "Performs DBSCAN clustering on raw point‑cloud data."
    DTDFVocab:inputTo DataPreProcessingEnabler
]

instance KalmanFilterTrackingModel : DTDFVocab:Model [
    base:desc "Applies Kalman‑filter tracking to clustered points to produce consistent object tracks."
    DTDFVocab:inputTo DataPreProcessingEnabler
]

instance ACCControlAlgorithmModel : DTDFVocab:Model [
    base:desc "Implements ACC control algorithm fulfilling ISO 15622 requirements."
    DTDFVocab:inputTo ControllingEnabler
]

instance Visualization3DModel : DTDFVocab:Model [
    base:desc "Renders 3D visualization of vehicle state, surrounding object tracks, and predicted driving path."
    DTDFVocab:inputTo VisualizationEnabler
]

instance VehicleStateReportingModel : DTDFVocab:Model [
    base:desc "Generates real‑time vehicle state reports and stores data in a SQL database."
    DTDFVocab:inputTo ReportingEnabler
]

instance VehicleDataStorageModel : DTDFVocab:Model [
    base:desc "Persists vehicle state and object track data in a SQL database."
    DTDFVocab:inputTo ReportingEnabler
]

// Enablers
instance DataTranslationEnabler : DTDFVocab:Enabler [
    base:desc "Serialises, units‑converts, and frames data between the PT and DT over ROS 2/UDP."
    DTDFVocab:enables DataMonitoringService
]

instance DataPreProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Executes DBSCAN clustering and Kalman‑filter tracking on LiDAR point‑cloud data."
    DTDFVocab:enables ComputationOffloadingService
]

instance ReportingEnabler : DTDFVocab:Enabler [
    base:desc "Generates real‑time reports and stores vehicle data in a SQL database."
    DTDFVocab:enables DataMonitoringService
]

instance ControllingEnabler : DTDFVocab:Enabler [
    base:desc "Runs the ACC control algorithm and delivers desired speed commands."
    DTDFVocab:enables ComputationOffloadingService
]

instance ActuationEnabler : DTDFVocab:Enabler [
    base:desc "Converts desired speed and steering‑angle signals into motor voltage signals for the Vedder Electronic Speed Controller and steering servo."
    DTDFVocab:enables RemoteManagementService
]

instance VisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Renders 3D visualization of vehicle, object tracks, and predicted path."
    DTDFVocab:enables DataMonitoringService
]

// Services
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "Provides real‑time monitoring of vehicle state, includes 3D visualization and reporting to operators."
    DTDFVocab:provides RealTimeVehicleStateInsight, PerformanceAnalysisInsight, VehicleTrackInsight
]

instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Offloads ACC algorithm computation, including lead‑vehicle detection and command delivery."
    DTDFVocab:provides DeliverDesiredSpeedCommandAction, VehicleTrackInsight
]

instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Allows operator to enable/disable ACC, adjust desired speed, and trigger emergency braking."
    DTDFVocab:provides EnableACCAction, AdjustDesiredSpeedAction, EmergencyBrakeAction
]

// Insights
instance RealTimeVehicleStateInsight : DTDFVocab:Insight [
    base:desc "Real‑time report of vehicle state and trajectory enabling anomaly detection."
]

instance PerformanceAnalysisInsight : DTDFVocab:Insight [
    base:desc "Analysis of ACC tracking accuracy and control performance informing sensor integration and tuning."
]

instance VehicleTrackInsight : DTDFVocab:Insight [
    base:desc "Object tracks and predicted driving path for path planning."
]

// Actions
instance EnableACCAction : DTDFVocab:Action [
    base:desc "Enable or disable the ACC subsystem."
    DTDFVocab:IsAutomatic false
]

instance AdjustDesiredSpeedAction : DTDFVocab:Action [
    base:desc "Set desired speed for the ACC subsystem."
    DTDFVocab:IsAutomatic false
]

instance EmergencyBrakeAction : DTDFVocab:Action [
    base:desc "Trigger emergency braking of the vehicle."
    DTDFVocab:IsAutomatic false
]

instance DeliverDesiredSpeedCommandAction : DTDFVocab:Action [
    base:desc "Deliver desired speed command from ACC control algorithm to the vehicle."
    DTDFVocab:IsAutomatic true
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "ACC outputs (desired speed, emergency braking commands) are serialised by the Data Translation FE, transmitted to PT, and handled by the Physical Twin Entity Actuation FE, which translates them into motor voltage commands for the speed controller and steering commands for the servo. Remote‐management UI commands (enable/disable ACC, set desired speed) follow the same routing path."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time operation with a maximum end‑to‑end latency of 100 ms from vehicle to DT as specified by R7; all system clocks are synchronized to an accuracy of 100 ms per R8; data is streamed continuously, with no predefined sampling frequency but meeting the real‑time requirement."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The constellation is organised as Physical Twin Entity (vehicle), Digital Twin Entity (cloud), and User Entity (3D visualization + control panel). Inter‑entity communication is realised over a Wi‑Fi network using ROS 2 topics transmitted via UDP, with the Data Translation FE orchestrating message framing, unit conversion, and timestamping."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT operates in the Operated lifecycle stage, gathering real‑time operational data, executing ACC control, and providing monitoring and remote‑management services. It does not model the Design or Manufacturing stages of the vehicle."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Real‑time data collection and 100 ms latency requirement ensure timely feedback; clock synchronization to 100 ms maintains data integrity; ACC algorithm follows ISO 15622 safety standards; data storage in a database and reporting provide traceability; however, no explicit V&V methodology is described beyond adherence to ISO requirements."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "PT and DT communicate over a Wi‑Fi link using ROS 2 topics carried over UDP. The Data Translation FE serialises and frames messages; Data Collection SE publishes vehicle state and object tracks with timestamps accurate to within 100 ms, conforming to the ISO 23247 Data Translation Format."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The Digital Twin Entity is deployed on a public cloud host; the Physical Twin Entity resides on the Jetson Orin Nano within the vehicle; the User Entity operates on an operator workstation or laptop, accessing the DT via the Data Translation and visualization components."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The architecture follows ISO 23247 (Digital Twin Manufacturing Framework) as the reference architecture, implements ISO 15622 for ACC control, and uses ROS 2 as open‑source middleware. OPC UA is referenced as a potential Data Translation method but not employed."
]

instance security_and_safety_considerations : DTDFVocab:SecuritySafety [
    base:desc "Safety‑critical nature emphasized by latency requirement (≤100 ms) and clock synchronization (≤100 ms); compliance with ISO 15622 ensures ACC safety; the DT operates within a controlled Wi‑Fi network, but explicit cybersecurity measures are not detailed in the document."
]
